//! FLV muxer — frame H.264 (AVC) + AAC into an FLV stream for RTMP.
//!
//! The codec payloads already exist (`h264_encode_compressed` → AVCC NALUs +
//! SPS/PPS, `aac` → AAC frames + AudioSpecificConfig). This module is *only*
//! container framing: the same inputs as [`crate::mux_av::mux_av_mp4`], wrapped
//! as FLV (header + AMF0 `onMetaData` + AVC/AAC sequence headers + per-frame
//! tags) so they can be pushed over RTMP. Pure std, wasm32-safe (no subprocess).
//!
//! This is the container half of the sovereign RTMP path; the remaining piece is
//! the RTMP protocol client (handshake + AMF0 connect/publish + chunk stream),
//! which needs a raw-TCP egress runtime (a swerve sliver, not a CF Worker).

fn w_u8(b: &mut Vec<u8>, v: u8) {
    b.push(v);
}
fn w_u24(b: &mut Vec<u8>, v: u32) {
    b.push(((v >> 16) & 0xFF) as u8);
    b.push(((v >> 8) & 0xFF) as u8);
    b.push((v & 0xFF) as u8);
}
fn w_u32(b: &mut Vec<u8>, v: u32) {
    b.extend_from_slice(&v.to_be_bytes());
}

/// AVCDecoderConfigurationRecord from SPS/PPS — identical to the MP4 `avcC` box,
/// reused here as the FLV AVC sequence header.
fn avc_decoder_config(sps: &[u8], pps: &[u8]) -> Vec<u8> {
    let mut b = Vec::new();
    w_u8(&mut b, 1); // configurationVersion
    w_u8(&mut b, *sps.get(1).unwrap_or(&0)); // AVCProfileIndication
    w_u8(&mut b, *sps.get(2).unwrap_or(&0)); // profile_compatibility
    w_u8(&mut b, *sps.get(3).unwrap_or(&0)); // AVCLevelIndication
    w_u8(&mut b, 0xFF); // 6 reserved bits + lengthSizeMinusOne = 3 (4-byte NAL length)
    w_u8(&mut b, 0xE1); // 3 reserved bits + numOfSequenceParameterSets = 1
    b.extend_from_slice(&(sps.len() as u16).to_be_bytes());
    b.extend_from_slice(sps);
    w_u8(&mut b, 1); // numOfPictureParameterSets
    b.extend_from_slice(&(pps.len() as u16).to_be_bytes());
    b.extend_from_slice(pps);
    b
}

fn amf0_str(b: &mut Vec<u8>, s: &str) {
    b.push(0x02); // string marker
    b.extend_from_slice(&(s.len() as u16).to_be_bytes());
    b.extend_from_slice(s.as_bytes());
}
fn amf0_key_number(b: &mut Vec<u8>, key: &str, n: f64) {
    b.extend_from_slice(&(key.len() as u16).to_be_bytes());
    b.extend_from_slice(key.as_bytes());
    b.push(0x00); // number marker
    b.extend_from_slice(&n.to_be_bytes());
}

/// The `onMetaData` script payload (AMF0 string + ECMA array of stream props).
fn on_metadata(width: u32, height: u32, fps: u32, sample_rate: u32, channels: u8) -> Vec<u8> {
    let mut b = Vec::new();
    amf0_str(&mut b, "onMetaData");
    b.push(0x08); // ECMA array marker
    let props: [(&str, f64); 8] = [
        ("duration", 0.0),
        ("width", width as f64),
        ("height", height as f64),
        ("framerate", fps as f64),
        ("videocodecid", 7.0), // AVC
        ("audiocodecid", 10.0), // AAC
        ("audiosamplerate", sample_rate as f64),
        ("audiochannels", channels as f64),
    ];
    b.extend_from_slice(&(props.len() as u32).to_be_bytes());
    for (k, v) in props {
        amf0_key_number(&mut b, k, v);
    }
    b.extend_from_slice(&[0x00, 0x00, 0x09]); // empty key + object-end marker
    b
}

/// Write one FLV tag (type + 24-bit size + 32-bit timestamp + stream id + data)
/// followed by its trailing PreviousTagSize.
fn write_tag(out: &mut Vec<u8>, tag_type: u8, timestamp: u32, data: &[u8]) {
    let start = out.len();
    w_u8(out, tag_type);
    w_u24(out, data.len() as u32);
    w_u24(out, timestamp & 0x00FF_FFFF);
    w_u8(out, ((timestamp >> 24) & 0xFF) as u8); // TimestampExtended
    w_u24(out, 0); // StreamID (always 0)
    out.extend_from_slice(data);
    let tag_size = (out.len() - start) as u32;
    w_u32(out, tag_size);
}

/// Mux H.264 (AVC) + AAC into a complete FLV stream.
///
/// - `sps`, `pps`: raw NAL bytes (incl. 1-byte header, no start code).
/// - `video_samples`: per-frame AVCC payload (NALUs length-prefixed, 4-byte BE) —
///   same as [`crate::mux_av::mux_av_mp4`]. All-intra ⇒ every frame is a keyframe.
/// - `asc`: AudioSpecificConfig (from `aac::encode_aac_lc`).
/// - `audio_frames`: raw AAC access units.
#[allow(clippy::too_many_arguments)]
pub fn mux_av_flv(
    sps: &[u8],
    pps: &[u8],
    video_samples: &[Vec<u8>],
    width: u32,
    height: u32,
    fps: u32,
    asc: &[u8],
    audio_frames: &[Vec<u8>],
    sample_rate: u32,
    channels: u8,
) -> Vec<u8> {
    let mut out = Vec::new();

    // FLV header: 'FLV', version 1, flags = audio|video (0x05), header size 9.
    out.extend_from_slice(b"FLV");
    w_u8(&mut out, 1);
    w_u8(&mut out, 0x05);
    w_u32(&mut out, 9);
    w_u32(&mut out, 0); // PreviousTagSize0

    // onMetaData (script tag).
    write_tag(&mut out, 0x12, 0, &on_metadata(width, height, fps, sample_rate, channels));

    // AVC sequence header (video tag): keyframe+AVC (0x17), AVCPacketType 0, cts 0.
    let mut seq = vec![0x17u8, 0x00, 0x00, 0x00, 0x00];
    seq.extend_from_slice(&avc_decoder_config(sps, pps));
    write_tag(&mut out, 0x09, 0, &seq);

    // AAC sequence header (audio tag): 0xAF (AAC/44k/16-bit/stereo nominal), AACPacketType 0.
    let mut aseq = vec![0xAFu8, 0x00];
    aseq.extend_from_slice(asc);
    write_tag(&mut out, 0x08, 0, &aseq);

    // Interleave A/V frames by timestamp.
    let frame_ms = if fps > 0 { 1000 / fps } else { 33 };
    let audio_ms = if sample_rate > 0 { 1024 * 1000 / sample_rate } else { 23 };
    let n = video_samples.len().max(audio_frames.len());
    for i in 0..n {
        if let Some(v) = video_samples.get(i) {
            // All-intra → every frame is a keyframe (0x17); AVCPacketType 1 (NALU), cts 0.
            let mut data = vec![0x17u8, 0x01, 0x00, 0x00, 0x00];
            data.extend_from_slice(v);
            write_tag(&mut out, 0x09, (i as u32) * frame_ms, &data);
        }
        if let Some(a) = audio_frames.get(i) {
            let mut data = vec![0xAFu8, 0x01]; // AAC, AACPacketType 1 (raw)
            data.extend_from_slice(a);
            write_tag(&mut out, 0x08, (i as u32) * audio_ms, &data);
        }
    }
    out
}

#[cfg(test)]
mod tests {
    use super::*;

    fn make_inputs() -> (Vec<u8>, Vec<u8>, Vec<Vec<u8>>, Vec<u8>, Vec<Vec<u8>>) {
        let sps = vec![0x67u8, 0x42, 0x00, 0x1E, 0xAB, 0xCD];
        let pps = vec![0x68u8, 0xCE, 0x38, 0x80];
        // AVCC samples: [4-byte length][NALU].
        let video = vec![vec![0, 0, 0, 2, 0x65, 0x88], vec![0, 0, 0, 2, 0x41, 0x99]];
        let asc = vec![0x12u8, 0x08];
        let audio = vec![vec![0xDEu8, 0xAD], vec![0xBEu8, 0xEF]];
        (sps, pps, video, asc, audio)
    }

    /// Parse the FLV back: signature, header, and that tags tile the buffer exactly
    /// with the right types in order — the structural contract a demuxer relies on.
    #[test]
    fn flv_is_well_formed() {
        let (sps, pps, video, asc, audio) = make_inputs();
        let flv = mux_av_flv(&sps, &pps, &video, 320, 240, 30, &asc, &audio, 44100, 2);

        assert_eq!(&flv[0..3], b"FLV", "signature");
        assert_eq!(flv[3], 1, "version");
        assert_eq!(flv[4], 0x05, "audio|video flags");
        assert_eq!(&flv[5..9], &[0, 0, 0, 9], "header size");
        assert_eq!(&flv[9..13], &[0, 0, 0, 0], "PreviousTagSize0");

        let mut pos = 13usize;
        let mut types = Vec::new();
        while pos + 11 <= flv.len() {
            let tt = flv[pos];
            let size = ((flv[pos + 1] as usize) << 16)
                | ((flv[pos + 2] as usize) << 8)
                | (flv[pos + 3] as usize);
            // PreviousTagSize must equal tag header (11) + data size.
            let prev_off = pos + 11 + size;
            let prev = ((flv[prev_off] as u32) << 24)
                | ((flv[prev_off + 1] as u32) << 16)
                | ((flv[prev_off + 2] as u32) << 8)
                | (flv[prev_off + 3] as u32);
            assert_eq!(prev as usize, 11 + size, "PreviousTagSize");
            types.push(tt);
            pos += 11 + size + 4;
        }
        assert_eq!(pos, flv.len(), "tags must tile the buffer exactly");

        // The three init tags, in order: script, AVC seq header, AAC seq header.
        assert_eq!(types[0], 0x12, "onMetaData first");
        assert_eq!(types[1], 0x09, "AVC sequence header");
        assert_eq!(types[2], 0x08, "AAC sequence header");
        // Plus a data tag per A/V frame.
        assert_eq!(types.iter().filter(|&&t| t == 0x09).count(), 1 + video.len());
        assert_eq!(types.iter().filter(|&&t| t == 0x08).count(), 1 + audio.len());
    }
}
